/* == EXEMPLE ================================================
 * Initialisation designee d'une struct Rect
 * {.champ = val} nomme les champs explicitement.
 * Les champs non mentionnes sont mis a 0.
 * =========================================================== */
typedef struct { int x, y, w, h; } Rect;

void example_demo(void) {
    Rect r1 = {.x = 10, .y = 20, .w = 100, .h = 50};
    Rect r2 = {.w = 200, .h = 100}; /* x=0, y=0 */
    Rect *rp = &(Rect){5, 5, 30, 30};
    printf("r1 = (%d,%d,%d,%d)\n", r1.x, r1.y, r1.w, r1.h);
    printf("r2 = (%d,%d,%d,%d)\n", r2.x, r2.y, r2.w, r2.h);
    printf("rp = (%d,%d,%d,%d)\n", rp->x, rp->y, rp->w, rp->h);
}
